class Solution:
    def minCostClimbingStairs(self, arr: List[int]) -> int:
        dp = [0]*len(arr)
        for i in range(2, len(arr)):
            dp[i] = arr[i] + min(dp[i-1], dp[i-2])
        return min(dp[-1], dp[-2])

solutions.cpp:
class Solution {
 public:
    int minCostClimbingStairs(vector<int>& arr) {
        int dp[arr.size()];
        for (int i = 2; i < arr.size(); i++) {
            dp[i] = arr[i] + min(dp[i-1], dp[i-2]);
        }
        return min(dp[arr.size()-1], dp[arr.size()-2]);
    }
};
